// Secure user session management - access tokens NOT stored
type UserSession struct {
	ID     uuid.UUID `json:"id"`
	UserID uuid.UUID `json:"user_id"`
	// SHA-256 hash of refresh token (64 hex chars)
	RefreshTokenHash string `json:"refresh_token_hash"`
	// Version number for token rotation tracking
	RefreshTokenVersion int32 `json:"refresh_token_version"`
	// Current access token JTI for immediate blacklisting
	CurrentJti uuid.UUID `json:"current_jti"`
	// Access token expiry time (typically 15 minutes)
	ExpiresAt time.Time `json:"expires_at"`
	// Refresh token expiry time (typically 7 days)
	RefreshExpiresAt time.Time       `json:"refresh_expires_at"`
	IpAddress        *netip.Addr     `json:"ip_address"`
	UserAgent        *string         `json:"user_agent"`
	DeviceInfo       json.RawMessage `json:"device_info"`
	IsActive         bool            `json:"is_active"`
	LastUsedAt       *time.Time      `json:"last_used_at"`
	RevokedAt        *time.Time      `json:"revoked_at"`
	CreatedAt        time.Time       `json:"created_at"`
	UpdatedAt        time.Time       `json:"updated_at"`
}

